def validate(args, output):
    s = args[0]
    if not isinstance(output, list):
        return False
    def is_pal(t):
        return t == t[::-1]
    seen = set()
    for part in output:
        if not isinstance(part, list):
            return False
        if any(not isinstance(p, str) for p in part):
            return False
        if ''.join(part) != s:
            return False
        if any(len(p) == 0 or not is_pal(p) for p in part):
            return False
        key = tuple(part)
        if key in seen:
            return False
        seen.add(key)
    # completeness: recompute every valid partition
    n = len(s)
    pal = [[False] * n for _ in range(n)]
    for i in range(n - 1, -1, -1):
        for j in range(i, n):
            if s[i] == s[j] and (j - i < 2 or pal[i + 1][j - 1]):
                pal[i][j] = True
    correct = set()
    def bt(start, cur):
        if start == n:
            correct.add(tuple(cur))
            return
        for end in range(start, n):
            if pal[start][end]:
                cur.append(s[start:end + 1])
                bt(end + 1, cur)
                cur.pop()
    bt(0, [])
    return seen == correct

