function validate(args, output) {
    const s = args[0];
    if (!Array.isArray(output)) return false;
    const isPal = (t) => { for (let a = 0, b = t.length - 1; a < b; a++, b--) if (t[a] !== t[b]) return false; return true; };
    const seen = new Set();
    for (const part of output) {
        if (!Array.isArray(part)) return false;
        if (part.some(p => typeof p !== 'string')) return false;
        if (part.join('') !== s) return false;
        if (part.some(p => p.length === 0 || !isPal(p))) return false;
        const key = JSON.stringify(part);
        if (seen.has(key)) return false;
        seen.add(key);
    }
    const n = s.length;
    const pal = Array.from({length: n}, () => new Array(n).fill(false));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = i; j < n; j++) {
            if (s[i] === s[j] && (j - i < 2 || pal[i + 1][j - 1])) pal[i][j] = true;
        }
    }
    const correct = new Set();
    const cur = [];
    function bt(start) {
        if (start === n) { correct.add(JSON.stringify(cur)); return; }
        for (let end = start; end < n; end++) {
            if (pal[start][end]) {
                cur.push(s.slice(start, end + 1));
                bt(end + 1);
                cur.pop();
            }
        }
    }
    bt(0);
    if (seen.size !== correct.size) return false;
    for (const k of seen) if (!correct.has(k)) return false;
    return true;
}

