class Solution:
    def partition(self, s):
        n = len(s)
        def is_pal(t):
            return t == t[::-1]
        res = []
        def bt(start, cur):
            if start == n:
                res.append(list(cur))
                return
            for end in range(start + 1, n + 1):
                piece = s[start:end]
                if is_pal(piece):
                    cur.append(piece)
                    bt(end, cur)
                    cur.pop()
        bt(0, [])
        res.sort()
        return res

