var partition = function(s) {
    const n = s.length;
    const pal = Array.from({length: n}, () => new Array(n).fill(false));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = i; j < n; j++) {
            if (s[i] === s[j] && (j - i < 2 || pal[i + 1][j - 1])) pal[i][j] = true;
        }
    }
    const res = [];
    const cur = [];
    function bt(start) {
        if (start === n) { res.push(cur.slice()); return; }
        for (let end = start; end < n; end++) {
            if (pal[start][end]) {
                cur.push(s.slice(start, end + 1));
                bt(end + 1);
                cur.pop();
            }
        }
    }
    bt(0);
    res.sort((a, b) => {
        const m = Math.min(a.length, b.length);
        for (let i = 0; i < m; i++) if (a[i] !== b[i]) return a[i] < b[i] ? -1 : 1;
        return a.length - b.length;
    });
    return res;
};
